import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import axiosInstance from '../axiosConfig';

const AdminDashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [reservations, setReservations] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [filterDate, setFilterDate] = useState('');
  const [filterName, setFilterName] = useState('');

  // Redirect if not logged in
  useEffect(() => {
    if (!user) navigate('/login');
  }, [user, navigate]);

  // Fetch all reservations
  useEffect(() => {
    const fetchReservations = async () => {
      setLoading(true);
      try {
        const response = await axiosInstance.get('/api/reservations', {
          headers: { Authorization: `Bearer ${user.token}` }
        });
        setReservations(response.data);
        setFiltered(response.data);
      } catch (err) {
        setError('Failed to load reservations.');
      } finally {
        setLoading(false);
      }
    };

    if (user) fetchReservations();
  }, [user]);

  // Filter by date or name
  useEffect(() => {
    let results = reservations;

    if (filterName) {
      results = results.filter(r =>
        r.customerName.toLowerCase().includes(filterName.toLowerCase())
      );
    }

    if (filterDate) {
      results = results.filter(r =>
        new Date(r.reservedDate).toLocaleDateString() ===
        new Date(filterDate).toLocaleDateString()
      );
    }

    setFiltered(results);
  }, [filterName, filterDate, reservations]);

  // Cancel a reservation
  const handleCancel = async (id) => {
    if (!window.confirm('Cancel this reservation?')) return;
    try {
      await axiosInstance.delete(`/api/reservations/${id}`, {
        headers: { Authorization: `Bearer ${user.token}` }
      });
      setReservations(reservations.filter(r => r._id !== id));
    } catch (err) {
      setError('Failed to cancel reservation.');
    }
  };

  if (loading) return (
    <div className="text-center mt-20 text-gray-500">Loading reservations...</div>
  );

  return (
    <div className="max-w-5xl mx-auto mt-10 px-4">
      <h1 className="text-3xl font-bold mb-6 text-blue-700">Admin Dashboard</h1>

      {error && (
        <div className="bg-red-100 text-red-700 p-3 rounded mb-4 text-sm">{error}</div>
      )}

      {/* Filters */}
      <div className="bg-white p-4 shadow rounded mb-6 flex flex-col sm:flex-row gap-4">
        <div className="flex-1">
          <label className="block text-sm font-medium mb-1">Filter by Name</label>
          <input
            type="text"
            placeholder="Search by customer name"
            value={filterName}
            onChange={(e) => setFilterName(e.target.value)}
            className="w-full p-2 border rounded"
          />
        </div>
        <div className="flex-1">
          <label className="block text-sm font-medium mb-1">Filter by Date</label>
          <input
            type="date"
            value={filterDate}
            onChange={(e) => setFilterDate(e.target.value)}
            className="w-full p-2 border rounded"
          />
        </div>
        <div className="flex items-end">
          <button
            onClick={() => { setFilterName(''); setFilterDate(''); }}
            className="bg-gray-200 text-gray-700 px-4 py-2 rounded hover:bg-gray-300 transition"
          >
            Clear
          </button>
        </div>
      </div>

      {/* Summary */}
      <p className="text-sm text-gray-500 mb-4">
        Showing {filtered.length} of {reservations.length} reservation(s)
      </p>

      {/* Reservations table */}
      {filtered.length === 0 ? (
        <div className="bg-white p-6 shadow rounded text-center text-gray-500">
          No reservations found.
        </div>
      ) : (
        <div className="bg-white shadow rounded overflow-x-auto">
          <table className="w-full text-sm">
            <thead className="bg-blue-700 text-white">
              <tr>
                <th className="p-3 text-left">Name</th>
                <th className="p-3 text-left">Date</th>
                <th className="p-3 text-left">Guests</th>
                <th className="p-3 text-left">Table</th>
                <th className="p-3 text-left">Status</th>
                <th className="p-3 text-left">Contact</th>
                <th className="p-3 text-left">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((r, i) => (
                <tr key={r._id} className={i % 2 === 0 ? 'bg-white' : 'bg-gray-50'}>
                  <td className="p-3">{r.customerName}</td>
                  <td className="p-3">{new Date(r.reservedDate).toLocaleString()}</td>
                  <td className="p-3">{r.numGuests}</td>
                  <td className="p-3">{r.tableId?.location || 'N/A'}</td>
                  <td className="p-3">
                    <span className={`px-2 py-1 rounded text-xs font-semibold
                      ${r.status === 'confirmed' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                      {r.status}
                    </span>
                  </td>
                  <td className="p-3 text-xs text-gray-500">{r.phoneNum}</td>
                  <td className="p-3">
                    <button
                      onClick={() => handleCancel(r._id)}
                      className="bg-red-500 text-white px-3 py-1 rounded hover:bg-red-600 transition text-xs"
                    >
                      Cancel
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
